SELECT TOP 1 COUNT(*) AS TOTAL_CITIES,
	AVG(WD.[TEMPERATURE]) AS AVG_TEMP,
	MAX(WD.[TEMPERATURE]) AS MAX_TEMP,
	MIN(WD.[TEMPERATURE]) AS MIN_TEMP 
FROM [WEATHER_DATAS] WD 
WHERE WD.[IsDeleted] = 0 
	AND WD.[LAST_UPDATED] > DATEADD(HOUR, -1,
	GETDATE()) 